import React, { useState } from 'react';
import './Nav.css';

const links = ['About', 'Skills', 'Experience', 'Projects', 'Education', 'Contact'];

export default function Nav({ scrolled }) {
  const [open, setOpen] = useState(false);

  return (
    <nav className={`nav ${scrolled ? 'nav--scrolled' : ''}`}>
      <div className="nav__inner container">
        <a href="#hero" className="nav__logo mono">
          <span className="nav__logo-bracket">&lt;</span>
          vp
          <span className="nav__logo-bracket">/&gt;</span>
        </a>

        <ul className={`nav__links ${open ? 'nav__links--open' : ''}`}>
          {links.map(l => (
            <li key={l}>
              <a href={`#${l.toLowerCase()}`} onClick={() => setOpen(false)}>
                {l}
              </a>
            </li>
          ))}
          <li>
            <a
              href="/Victoria_Pham_Resume_SRE_Cloud.pdf"
              target="_blank"
              rel="noreferrer"
              className="nav__resume-btn"
            >
              Resume
            </a>
          </li>
        </ul>

        <button
          className={`nav__hamburger ${open ? 'nav__hamburger--open' : ''}`}
          onClick={() => setOpen(!open)}
          aria-label="Toggle menu"
        >
          <span /><span /><span />
        </button>
      </div>
    </nav>
  );
}
